{"file_text": "<div class="password-panel">
    <button class="password-toggle" @onclick="ToggleExpanded">
        <span class="toggle-icon">@(IsExpanded ? "▾" : "▸")</span>
        Change Password
    </button>

    @if (IsExpanded)
    {
        <div class="password-form">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_errorMessage))
            {
                <div class="alert alert-danger py-2">@_errorMessage</div>
            }
            @if (_showSuccess)
            {
                <div class="alert alert-success py-2">Password updated successfully.</div>
            }

            <button class="btn btn-primary btn-sm" @onclick="UpdatePassword" disabled="@_isSaving">
                @(_isSaving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded { get; set; }
    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private string? _errorMessage;
    private bool _showSuccess;
    private bool _isSaving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task UpdatePassword()
    {
        _errorMessage = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            _errorMessage = "Current password is required.";
            return;
        }
        if (NewPassword.Length < 8)
        {
            _errorMessage = "New password must be at least 8 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            _errorMessage = "New passwords do not match.";
            return;
        }

        _isSaving = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            _showSuccess = true;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _isSaving = false;
        }
    }
}
", "path": "/tmp/sv-8274288a4dfa418587a2f5cf079c2599/Components/Pages/Settings/ChangePasswordPanel.razor"}

