@inject ISettingsService SettingsService

<div class="profile-section">
    <h4>Profile</h4>

    @if (_isLoading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <div class="profile-layout">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url text-muted small mt-1">@_avatarUrl</div>
            </div>

            <div class="profile-fields">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="3" @bind="_bio"></textarea>
                </div>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success py-2">@_successMessage</div>
                }

                <div class="d-flex gap-2">
                    <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_isSaving">
                        @(_isSaving ? "Saving…" : "Save Changes")
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                        Discard Changes
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private UserProfile? _savedProfile;
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _isLoading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        _successMessage = null;
        _isSaving = true;

        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;

        _isSaving = false;
        _successMessage = "Profile saved successfully!";
    }

    private void DiscardChanges()
    {
        _successMessage = null;
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

.profile-section h4 {
    margin-bottom: 1.25rem;
    font-weight: 600;
}

.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    flex-shrink: 0;
    text-align: center;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    background: #e9ecef;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-url {
    max-width: 140px;
    word-break: break-all;
}

.profile-fields {
    flex: 1;
    min-width: 0;
}

@inject ISettingsService SettingsService

<div class="notifications-section">
    <h4>Notifications</h4>

    @if (_isLoading)
    {
        <p class="text-muted">Loading preferences…</p>
    }
    else
    {
        <div class="toggle-group">
            <label class="toggle-row">
                <span>Email Notifications</span>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                </div>
            </label>
            <label class="toggle-row">
                <span>Push Notifications</span>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                </div>
            </label>
            <label class="toggle-row">
                <span>Weekly Digest</span>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                </div>
            </label>
        </div>

        <h5 class="mt-4 mb-3">Muted Channels</h5>
        <div class="channel-list">
            @foreach (var channel in _channels)
            {
                <label class="channel-item">
                    <input type="checkbox" class="form-check-input"
                           checked="@channel.IsMuted"
                           @onchange="e => channel.IsMuted = (bool)(e.Value ?? false)" />
                    <span>#@channel.Name</span>
                </label>
            }
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success py-2 mt-3">@_successMessage</div>
        }

        <button class="btn btn-primary mt-3" @onclick="SavePreferences" disabled="@_isSaving">
            @(_isSaving ? "Saving…" : "Save Preferences")
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelModel> _channels = [];
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels
            .Select(c => new ChannelModel { Name = c, IsMuted = true })
            .ToList();
        _isLoading = false;
    }

    private async Task SavePreferences()
    {
        _successMessage = null;
        _isSaving = true;

        var mutedChannels = _channels.Where(c => c.IsMuted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);

        _isSaving = false;
        _successMessage = "Preferences saved successfully!";
    }

    private class ChannelModel
    {
        public string Name { get; set; } = "";
        public bool IsMuted { get; set; }
    }
}

.notifications-section h4 {
    margin-bottom: 1.25rem;
    font-weight: 600;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.625rem 0.75rem;
    border-radius: 0.375rem;
    cursor: pointer;
}

.toggle-row:hover {
    background: #f8f9fa;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.375rem 0.75rem;
    border-radius: 0.375rem;
    cursor: pointer;
}

.channel-item:hover {
    background: #f8f9fa;
}

@inject ISettingsService SettingsService

<div class="security-section">
    <h4>Security</h4>

    @if (_isLoading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <div class="tfa-panel">
            <div class="tfa-row">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="tfa-status">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark">Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <h5 class="mt-4 mb-3">Active Sessions</h5>
        <ActiveSessionsTable Sessions="_sessions" OnRevoke="HandleRevoke" />
    }
</div>

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private bool _isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _isLoading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevoke(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

.security-section h4 {
    margin-bottom: 1.25rem;
    font-weight: 600;
}

.tfa-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1rem;
    margin-bottom: 1.5rem;
}

.tfa-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.tfa-status {
    margin-top: 0.25rem;
}

@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4>Appearance</h4>

    @if (_isLoading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="appearance-layout">
            <div class="appearance-controls">
                <div class="mb-4">
                    <label class="form-label fw-semibold">Theme</label>
                    <div class="d-flex gap-3">
                        @foreach (var theme in _themes)
                        {
                            <label class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <span class="form-check-label">@theme</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <label class="form-label fw-semibold">Font Size</label>
                    <div class="d-flex gap-3">
                        @foreach (var size in _fontSizes)
                        {
                            <label class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <span class="form-check-label">@size</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <label class="form-label fw-semibold">Language</label>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <label class="toggle-row">
                        <span class="fw-semibold">Compact Mode</span>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </label>
                </div>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success py-2">@_successMessage</div>
                }

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_isSaving">
                    @(_isSaving ? "Saving…" : "Save")
                </button>
            </div>

            <div class="preview-area">
                <h6 class="fw-semibold mb-2">Live Preview</h6>
                <div class="preview-card @PreviewThemeClass" style="font-size: @PreviewFontSize;">
                    <div class="preview-header">Dashboard</div>
                    <p class="preview-text">
                        This is how your content will look with
                        <strong>@_theme</strong> theme,
                        <strong>@_fontSize</strong> font,
                        and compact mode <strong>@(_compactMode ? "on" : "off")</strong>.
                    </p>
                    <div class="preview-items" style="gap: @(_compactMode ? "0.25rem" : "0.5rem");">
                        <div class="preview-item">📊 Analytics</div>
                        <div class="preview-item">📝 Reports</div>
                        <div class="preview-item">⚙️ Settings</div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _isLoading = false;
    }

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

