@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4>Appearance</h4>

    @if (_isLoading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="appearance-layout">
            <div class="appearance-controls">
                <div class="mb-4">
                    <label class="form-label fw-semibold">Theme</label>
                    <div class="d-flex gap-3">
                        @foreach (var theme in _themes)
                        {
                            <label class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <span class="form-check-label">@theme</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <label class="form-label fw-semibold">Font Size</label>
                    <div class="d-flex gap-3">
                        @foreach (var size in _fontSizes)
                        {
                            <label class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <span class="form-check-label">@size</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <label class="form-label fw-semibold">Language</label>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <label class="toggle-row">
                        <span class="fw-semibold">Compact Mode</span>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </label>
                </div>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success py-2">@_successMessage</div>
                }

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_isSaving">
                    @(_isSaving ? "Saving…" : "Save")
                </button>
            </div>

            <div class="preview-area">
                <h6 class="fw-semibold mb-2">Live Preview</h6>
                <div class="preview-card @PreviewThemeClass" style="font-size: @PreviewFontSize;">
                    <div class="preview-header">Dashboard</div>
                    <p class="preview-text">
                        This is how your content will look with
                        <strong>@_theme</strong> theme,
                        <strong>@_fontSize</strong> font,
                        and compact mode <strong>@(_compactMode ? "on" : "off")</strong>.
                    </p>
                    <div class="preview-items" style="gap: @(_compactMode ? "0.25rem" : "0.5rem");">
                        <div class="preview-item">📊 Analytics</div>
                        <div class="preview-item">📝 Reports</div>
                        <div class="preview-item">⚙️ Settings</div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

