@inject ISettingsService SettingsService

<div class="profile-section">
    <h4>Profile</h4>

    @if (_isLoading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <div class="profile-layout">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url text-muted small mt-1">@_avatarUrl</div>
            </div>

            <div class="profile-fields">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="3" @bind="_bio"></textarea>
                </div>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success py-2">@_successMessage</div>
                }

                <div class="d-flex gap-2">
                    <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_isSaving">
                        @(_isSaving ? "Saving…" : "Save Changes")
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                        Discard Changes
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private UserProfile? _savedProfile;
    private bool _isLoading = true;
    private bool _isSaving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _isLoading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        _successMessage = null;
        _isSaving = true;

        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;

        _isSaving = false;
        _successMessage = "Profile saved successfully!";
    }

    private void DiscardChanges()
    {
        _successMessage = null;
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

